using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCharge_ReturnsUniqueChargeId()
    {
        var result1 = await _gateway.ChargeAsync("tok_visa_1", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_visa_2", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_EmptyOrWhitespaceToken_ThrowsArgumentException(string token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    [DataRow(0.0)]
    [DataRow(-5.0)]
    public async Task ChargeAsync_ZeroOrNegativeAmount_ThrowsArgumentOutOfRangeException(double amount)
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 25.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 999_999.99m);

        Assert.IsTrue(result.Success);
    }
}

[TestClass]
public sealed class PaymentGatewayRefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new PaymentGateway();

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_ValidRefund_ReturnsUniqueRefundId()
    {
        var result1 = await _gateway.RefundAsync("ch_charge_1");
        var result2 = await _gateway.RefundAsync("ch_charge_2");

        Assert.AreNotEqual(result1.RefundId, result2.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_EmptyOrWhitespaceChargeId_ThrowsArgumentException(string chargeId)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId));
    }

    [TestMethod]
    public async Task RefundAsync_NonexistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        await _gateway.RefundAsync("ch_already_refunded");
        var result = await _gateway.RefundAsync("ch_already_refunded");

        Assert.IsFalse(result.Success);
    }
}

